const resp = $json;
const body = resp?.body ?? resp;

const statusCode = resp?.statusCode ?? body?.statusCode ?? null;
const ok = statusCode === null || (statusCode >= 200 && statusCode < 300);

const standardId =
  body?.data?.id ??
  body?.id ??
  body?.standard?.id ??
  null;

return [{
  json: {
    standard_id: standardId,
    standard_ok: !!standardId && ok,
    http_ok: ok,
    status_code: statusCode,
    standard_response: resp
  }
}];

const resp = $json;
const body = resp?.body ?? resp;

const statusCode = resp?.statusCode ?? body?.statusCode ?? null;
const ok = statusCode === null || (statusCode >= 200 && statusCode < 300);

const programId =
  body?.data?.id ??
  body?.id ??
  body?.program?.id ??
  null;

return [{
  json: {
    program_id: programId,
    program_ok: !!programId && ok,
    http_ok: ok,
    status_code: statusCode,
    program_response: resp
  }
}];

const standardId = $('Normalize Standard Result').first().json.standard_id;
const programId = $('Normalize Program Result').first().json.program_id;
const controls = $('Set OpenGRC Config').first().json.controls;

return controls.map((c, index) => ({
  json: {
    sequence: index + 1,
    code: c.code,
    name: c.name,
    standard_id: standardId,
    program_id: programId,

    control_payload: {
      code: c.code,
      identifier: c.code,
      standard_id: standardId,
      enforcement: "mandatory",
      type: "preventive",
      category: "operational",
      title: c.name,
      description: c.description,
      discussion: c.reference,
      test_plan: c.evidence,
      status: "active"
    },

    implementation_template: {
      code: `${c.code}-IMPL`,
      identifier: `${c.code}-IMPL`,
      title: `Implementation - ${c.code} - ${c.name}`,
      description: `${c.implementation}\n\nRequired evidence: ${c.evidence}`,
      status: "implemented"
    }
  }
}));

const prepared = $item(0).$node["Prepare Controls"].json;
const controlResp = $json;
const body = controlResp?.body ?? controlResp;

const statusCode = controlResp?.statusCode ?? body?.statusCode ?? null;
const httpOk = statusCode === null || (statusCode >= 200 && statusCode < 300);

const controlId =
  body?.data?.id ??
  body?.id ??
  body?.control?.id ??
  null;

if (!httpOk || !controlId) {
  return [{
    json: {
      skipped: true,
      control_created: false,
      reason: !httpOk ? "control create HTTP failure" : "control creation response missing id",
      code: prepared.code,
      control_name: prepared.name,
      status_code: statusCode,
      control_response: controlResp
    }
  }];
}

const payload = {
  ...prepared.implementation_template,
  control_id: controlId
};

if (prepared.standard_id) payload.standard_id = prepared.standard_id;
if (prepared.program_id) payload.program_id = prepared.program_id;

return [{
  json: {
    skipped: false,
    control_created: true,
    code: prepared.code,
    control_name: prepared.name,
    control_id: controlId,
    implementation_payload: payload
  }
}];

const resp = $json;
const body = resp?.body ?? resp;

const statusCode = resp?.statusCode ?? body?.statusCode ?? null;
const httpOk = statusCode === null || (statusCode >= 200 && statusCode < 300);

const implementationId =
  body?.data?.id ??
  body?.id ??
  body?.implementation?.id ??
  null;

return [{
  json: {
    skipped: false,
    implementation_created: !!implementationId && httpOk,
    implementation_id: implementationId,
    http_ok: httpOk,
    status_code: statusCode,
    implementation_response: resp
  }
}];

const items = $input.all();

const skipped = items.filter(i => i.json.skipped === true);
const created = items.filter(i => i.json.implementation_created === true);
const failedImplementation = items.filter(i =>
  i.json.skipped !== true &&
  i.json.implementation_created === false
);

return [{
  json: {
    workflow: "OpenGRC FCC Control Set Bootstrap - Production Ready",
    created_at: new Date().toISOString(),
    total_items: items.length,
    implementations_created: created.length,
    skipped_controls: skipped.length,
    failed_implementation_creates: failedImplementation.length,
    details: items.map((item, i) => ({
      index: i + 1,
      skipped: item.json.skipped ?? false,
      control_created: item.json.control_created ?? null,
      implementation_created: item.json.implementation_created ?? null,
      implementation_id: item.json.implementation_id ?? null,
      reason: item.json.reason ?? null,
      status_code: item.json.status_code ?? null,
      code: item.json.code ?? null,
      control_name: item.json.control_name ?? null,
      response: item.json
    })),
    note: "Production-ready path: skipped controls and implementation results are merged before summary. Replace the token placeholder before running."
  }
}];
